"use client";

import { Accordion as AccordionPrimitive } from "@base-ui/react/accordion";
import { ChevronDownIcon } from "lucide-react";

import { cx, x } from "@/lib/utils";

import { styles } from "./accordion.stylex";

const Accordion = (
  props: React.ComponentProps<typeof AccordionPrimitive.Root>
) => <AccordionPrimitive.Root data-slot="accordion" {...props} />;

const AccordionItem = ({
  className,
  style,
  ...props
}: Omit<React.ComponentProps<typeof AccordionPrimitive.Item>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.item);
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    />
  );
};

const AccordionTrigger = ({
  className,
  style,
  children,
  ...props
}: Omit<
  React.ComponentProps<typeof AccordionPrimitive.Trigger>,
  "className"
> & { className?: string }) => {
  const header = x(styles.header);
  const trigger = x(styles.trigger);
  return (
    <AccordionPrimitive.Header
      className={header.className}
      style={header.style}
    >
      <AccordionPrimitive.Trigger
        data-slot="accordion-trigger"
        className={cx(trigger.className, className)}
        style={{ ...trigger.style, ...style }}
        render={(renderProps, state) => (
          <button type="button" {...renderProps}>
            {children}
            <ChevronDownIcon
              {...x(styles.chevron, state.open && styles.chevronOpen)}
            />
          </button>
        )}
        {...props}
      />
    </AccordionPrimitive.Header>
  );
};

const AccordionContent = ({
  className,
  style,
  children,
  ...props
}: Omit<React.ComponentProps<typeof AccordionPrimitive.Panel>, "className"> & {
  className?: string;
}) => {
  const p = x(styles.panel);
  const inner = x(styles.panelInner);
  return (
    <AccordionPrimitive.Panel
      data-slot="accordion-content"
      className={cx(p.className, className)}
      style={{ ...p.style, ...style }}
      {...props}
    >
      <div className={inner.className} style={inner.style}>
        {children}
      </div>
    </AccordionPrimitive.Panel>
  );
};

export { Accordion, AccordionContent, AccordionItem, AccordionTrigger };

import * as stylex from "@stylexjs/stylex";

import { colors, radius } from "../tokens.stylex";

export const styles = stylex.create({
  chevron: {
    color: colors.mutedForeground,
    flexShrink: 0,
    height: "1rem",
    marginTop: "0.125rem",
    pointerEvents: "none",
    transition: "transform 0.2s ease-in-out",
    width: "1rem",
  },
  chevronOpen: {
    transform: "rotate(180deg)",
  },
  header: {
    display: "flex",
    margin: 0,
  },
  item: {
    borderBottomColor: colors.border,
    borderBottomStyle: "solid",
    borderBottomWidth: "1px",
  },
  panel: {
    fontSize: "0.875rem",
    overflow: "hidden",
    transition: "height 0.2s ease-in-out",
  },
  panelInner: {
    paddingBottom: "1rem",
    paddingTop: 0,
  },
  trigger: {
    alignItems: "flex-start",
    background: "none",
    borderRadius: radius.md,
    borderWidth: 0,
    boxShadow: {
      ":focus-visible": `0 0 0 3px color-mix(in oklab, ${colors.ring} 50%, transparent)`,
      default: null,
    },
    color: colors.foreground,
    cursor: "pointer",
    display: "flex",
    flex: 1,
    fontSize: "0.875rem",
    fontWeight: 500,
    gap: "1rem",
    justifyContent: "space-between",
    outline: "none",
    paddingBottom: "1rem",
    paddingTop: "1rem",
    textAlign: "start",
    textDecorationLine: { ":hover": "underline", default: "none" },
    transition: "all 0.15s ease-in-out",
    width: "100%",
  },
});
